import{_ as a,o,c as t,ag as r}from"./chunks/framework.DEqXEGcv.js";const u=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"en/docs/reference/faq.md","filePath":"en/docs/reference/faq.md"}'),i={name:"en/docs/reference/faq.md"};function s(n,e,l,c,h,d){return o(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><h3 id="can-t-access-after-installation" tabindex="-1">Can&#39;t access after installation? <a class="header-anchor" href="#can-t-access-after-installation" aria-label="Permalink to &quot;Can&#39;t access after installation?&quot;">​</a></h3><p>Check the following:</p><ol><li>Is the RDE service running: <code>sudo systemctl status rde</code></li><li>Is the port in use: <code>sudo ss -tlnp | grep :80</code></li><li>Is the firewall allowing the port: <code>sudo ufw allow 80</code></li></ol><h3 id="which-operating-systems-are-supported" tabindex="-1">Which operating systems are supported? <a class="header-anchor" href="#which-operating-systems-are-supported" aria-label="Permalink to &quot;Which operating systems are supported?&quot;">​</a></h3><p>Currently supports Debian/Ubuntu (DEB package provided). Other Linux distributions can be compiled from source.</p><h3 id="how-to-update-to-the-latest-version" tabindex="-1">How to update to the latest version? <a class="header-anchor" href="#how-to-update-to-the-latest-version" aria-label="Permalink to &quot;How to update to the latest version?&quot;">​</a></h3><pre><code>wget https://github.com/ruizi-store/rde/releases/latest/download/rde_amd64.deb
sudo apt install ./rde_amd64.deb
</code></pre><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><h3 id="docker-app-store-doesn-t-show-containers" tabindex="-1">Docker App Store doesn&#39;t show containers? <a class="header-anchor" href="#docker-app-store-doesn-t-show-containers" aria-label="Permalink to &quot;Docker App Store doesn&#39;t show containers?&quot;">​</a></h3><p>Make sure Docker is installed and the RDE user has Docker permissions:</p><pre><code>sudo usermod -aG docker $USER
</code></pre><h3 id="file-upload-fails" tabindex="-1">File upload fails? <a class="header-anchor" href="#file-upload-fails" aria-label="Permalink to &quot;File upload fails?&quot;">​</a></h3><ul><li>Check if disk space is sufficient</li><li>Large file uploads support TUS resumable upload, refresh page to resume</li><li>Check if reverse proxy limits request body size (Nginx needs <code>client_max_body_size</code>)</li></ul><h3 id="terminal-connection-drops" tabindex="-1">Terminal connection drops? <a class="header-anchor" href="#terminal-connection-drops" aria-label="Permalink to &quot;Terminal connection drops?&quot;">​</a></h3><p>The terminal uses WebSocket connections. Ensure:</p><ol><li>Reverse proxy correctly forwards WebSocket (configure <code>Upgrade</code> header)</li><li>Reverse proxy doesn&#39;t have too short a timeout</li></ol><h3 id="how-to-change-the-port" tabindex="-1">How to change the port? <a class="header-anchor" href="#how-to-change-the-port" aria-label="Permalink to &quot;How to change the port?&quot;">​</a></h3><p>Edit <code>/etc/rde/conf.conf</code> to modify the <code>port</code> option, then restart the service.</p><h2 id="premium-services" tabindex="-1">Premium Services <a class="header-anchor" href="#premium-services" aria-label="Permalink to &quot;Premium Services&quot;">​</a></h2><h3 id="docker-image-pull-fails" tabindex="-1">Docker image pull fails? <a class="header-anchor" href="#docker-image-pull-fails" aria-label="Permalink to &quot;Docker image pull fails?&quot;">​</a></h3><ol><li>Check network connection</li><li>Try using mirror acceleration (see <a href="/en/docs/guide/i18n.html">i18n &amp; Mirror Acceleration</a>)</li></ol><h3 id="how-to-check-membership-expiry" tabindex="-1">How to check membership expiry? <a class="header-anchor" href="#how-to-check-membership-expiry" aria-label="Permalink to &quot;How to check membership expiry?&quot;">​</a></h3><p>Check &quot;Membership Info&quot; in RDE settings, or log in to the membership store.</p><h2 id="more-questions" tabindex="-1">More Questions <a class="header-anchor" href="#more-questions" aria-label="Permalink to &quot;More Questions&quot;">​</a></h2><p>Have more questions? Join our community to connect with us.</p>`,27)])])}const m=a(i,[["render",s]]);export{u as __pageData,m as default};
